        if (!safe) {
            throw new Error("zip_core.readZip: unsafe entry name in archive: " + name);
        }
        var bytes2 = raw[name];
        if (bytes2.length > maxEntrySize) {
            throw new Error("zip_core.readZip: entry " + safe + " size " + bytes2.length
