    // Enforce limits pre-inflate via fflate's per-entry filter callback,
    // which runs against central-directory metadata BEFORE the entry is
    // decompressed. Returning false skips, but we throw on breach so a
    // malicious archive can't be silently truncated. fflate's filter file
    // object exposes: name, size (compressed), originalSize (uncompressed).
    var count = 0;
    var totalUncompressed = 0;
    var safeNames = {};
    var limitErr = null;
    function filter(file) {
        if (limitErr) { return false; }
        count++;
        if (count > maxFileCount) {
            limitErr = new Error("zip_core.readZip: file count exceeds maxFileCount=" + maxFileCount);
            throw limitErr;
        }
        var safe = sanitizeZipPath(file.name);
        if (!safe) {
            limitErr = new Error("zip_core.readZip: unsafe entry name in archive: " + file.name);
            throw limitErr;
        }
        var uncompressed = file.originalSize || 0;
        if (uncompressed > maxEntrySize) {
            limitErr = new Error("zip_core.readZip: entry " + safe + " size " + uncompressed
                + " exceeds maxEntrySize=" + maxEntrySize);
            throw limitErr;
        }
        totalUncompressed += uncompressed;
        if (totalUncompressed > maxTotalSize) {
            limitErr = new Error("zip_core.readZip: uncompressed total " + totalUncompressed
                + " exceeds maxTotalSize=" + maxTotalSize);
            throw limitErr;
        }
        var compressed = file.size || 0;
        if (compressed > 0) {
            var entryRatio = uncompressed / compressed;
            if (entryRatio > maxRatio) {
                limitErr = new Error("zip_core.readZip: entry " + safe + " compression ratio "
                    + entryRatio.toFixed(1) + " exceeds maxRatio=" + maxRatio);
                throw limitErr;
            }
        }
        safeNames[file.name] = safe;
        return true;
    }

    var raw;
    try {
        raw = fflate.unzipSync(u8, { filter: filter });
    } catch (e) {
        if (limitErr) { throw limitErr; }
        throw new Error("zip_core.readZip: fflate unzipSync failed: "
            + ((e && e.message) || String(e)));
    }

    var ratio = u8.length > 0 ? (totalUncompressed / u8.length) : 0;
    if (ratio > maxRatio) {
        throw new Error("zip_core.readZip: compression ratio " + ratio.toFixed(1)
            + " exceeds maxRatio=" + maxRatio);
    }

    var out = {};
    var keys = Object.keys(raw);
    for (var j = 0; j < keys.length; j++) {
        var name = keys[j];
        out[safeNames[name] || name] = raw[name];
    }
    return out;
}

